function calculateAngle(p1, vertex, p2) {
  const v1 = { 
    x: p1.x - vertex.x, 
    y: p1.y - vertex.y 
  };
  const v2 = { 
    x: p2.x - vertex.x, 
    y: p2.y - vertex.y 
  };
  
  const dot = v1.x*v2.x + v1.y*v2.y;
  const mag1 = Math.sqrt(v1.x**2 + v1.y**2);
  const mag2 = Math.sqrt(v2.x**2 + v2.y**2);
  
  const cos = Math.max(-1, Math.min(1, 
    dot / (mag1 * mag2)));
  return Math.acos(cos) * (180 / Math.PI);
}

